import route_static from "./routes/static";

import { static_theme_css } from "./routes/static";
import { dividendCalender } from "./routes/dividend_calender";
import { dashboardAlpaca } from "./routes/dashboard";
import { evaluateOrders, openOrders } from "./routes/orders";

const PAPER_TRADING = false;

const credentials = PAPER_TRADING
    ? AlpacaCredentials.credentials_ts_paper
    : AlpacaCredentials.credentials_ts_live;

export default async (port: number = 8123) => {
    let positions: Position[] = [];
    let symbolDictionary: SymbolDictionary = {};
    let activitiesStat: ActivitiesStat = {
