    // process.exit(0);

    interface StartupLog {
        positions: Position[];

        cash: number;
        long_market_value: number;
        short_market_value: number;
        buying_power: number;
        portfolio_value: number;
        csd: number;
        fee: number;
        interest: number;
        div: number;
        divnra: number;
        div_minus: number;
        net: number;
    }

    function writePositions(positions: Position[]) {
        const cash = account?.cash;
        const long_market_value = account.long_market_value;
        const short_market_value = account.short_market_value;
        const bp = account.buying_power;
        const pv = account.portfolio_value;
        const csd = activitiesStat?.histogram?.["CSD"]?.sum;
        const fee = activitiesStat?.histogram?.["FEE"]?.sum;
        const interest = activitiesStat?.histogram?.["INT"]?.sum;

        const div = activitiesStat?.histogram?.["DIV"]?.sum;
        const divnra = activitiesStat?.histogram?.["DIVNRA"]?.sum;

        const div_minus = div + (divnra + interest + fee); // fees etc are negative!
        const net = pv - csd;

        const data: StartupLog = {
            cash,
            long_market_value,
            short_market_value,
            buying_power: bp,
            portfolio_value: pv,
            csd,
            fee,
            interest,
            div,
            divnra,
            div_minus,
            net,
            positions,
        };

        const jsonContent = JSON.stringify(data);
        // console.log("wp", jsonContent)

        const timestamp = formatDateSortableMinute();
        const fn = "data/alpaca_cache/" +
            replaceIllegalCharactersForFilename("alpaca_live__" + timestamp) +
            ".json";
        // console.log("wpfn", fn)
        writeFile(fn, jsonContent);

        return data;
    }

    function writeFile(filename: string, content: string) { //positions: Position[]) {
        fs.writeFile(filename, content, "utf8", function (err: any) {
            if (err) {
                console.log(
                    "An error occured while writing JSON Object to File.",
                );
                return console.log(err);
            }

            console.log("JSON file has been saved.", filename);
        });
    }

    async function loadAssets(): Promise<Asset[]> {
        assets = await client.getAssets();
        // client.getSnapshots({})
        return assets;
    }

    function lookupId(id: string): any {
        const r = assets.find((a) => a.id === id);
        return r;
    }

    async function refreshPositions() {
        symbolDictionary = {};
        // console.log("asse", assets)
        positions = await client.getPositions();
        // console.log('Current Account:', account)
        console.log("buying power:", account.buying_power); // number
