        var delta = 0;
        positions.forEach((position) => {
            const {
                symbol,
                market_value,
                cost_basis,
                avg_entry_price,
                current_price,
            } = position;
            symbolDictionary[symbol] = position;
            const winLoss = (market_value || 0) - cost_basis;
            delta += winLoss;

            console.log(
                `Symbol ${symbol} ${winLoss} | avg_entry: ${avg_entry_price} current price: ${current_price}`,
            );
        });
        console.log("delta", delta);

        delta_positions = delta;
    }

    function td_a(url: string, text: string) {
        return `
<td>
    <a href="${url}"  target="_blank"  rel="noopener noreferrer">${text}</a>
</td>`;
    }

    function tt(text: string, color?: string) {
        if (color) {
            return `<td style="background-color:${color};">${text}</a></td>`;
        }
        return `<td>${text}</a></td>`;
    }

    //
    // ${td_a(`https://www.tradingview.com/chart/5K2nT7d3/?symbol=${symbol}`, "<img  style='height: 1em;' src='https://avatars.githubusercontent.com/u/7644688?s=200&v=4' />" + symbol)}

    async function serverFn(requ: any) {
        const { url } = requ;
        const baseUrl = url.toLocaleLowerCase().split("?")[0];

        console.log("serverFn routes...", url);

        try {
            switch (baseUrl) {
                case "/dividend_calender":
                    return dividendCalender(requ, activitiesStat);
                case "/dashboard":
                    console.log("requ dashboard");
                    return dashboardAlpaca(
                        requ,
                        client,
                        assets,
                        positions,
                        activitiesStat,
                        account,
                    );
                case "/list_assets":
                    return route_list_assets(requ, assets);

                case "/ensure":
                    return ensure_symbol(requ, orders, assets);

                case "/open-orders":
                    return await openOrders(
                        requ,
                        client,
                        orders,
                        assets,
                        positions,
                    );

                case "/evaluate-orders":
                    return await evaluateOrders(
                        requ,
                        client,
                        orders,
                        assets,
                        positions,
                    );
            }

