function smartQuantityStr(quantity: number, fixedDigits: number = 2) {
  if (quantity - Math.floor(quantity) > 0) {
    return quantity.toFixed(fixedDigits);
  }
  return quantity.toFixed(0);
}

type SortOrder = "ascending" | "descending";
type SortType =
  | "profit-loss"
  | "profit-loss-percentage"
  | "symbol"
  | "market-value"
  | "cost-basis"
  | "side"
  | "current-price"
  | "quantity";

function sorter(sortType: SortType, sortOrder: SortOrder) {
  const sortOrderMultiplier = sortOrder === "ascending" ? 1 : -1;

  switch (sortType) {
    case "cost-basis":
      return (a: Position, b: Position) => {
        return (
          sortOrderMultiplier * (b.cost_basis ?? 0) - (a.market_value ?? 0)
        );
      };
  }
}

